// Parse incoming failure data from test runner
const input = $input.first().json;

const failures = input.failures || [];
const invocationId = input.invocation_id || 'unknown';
const agentId = input.agent_id || 'agent_8001kdgp7qbyf4wvhs540be78vew';
const totalTests = input.total_tests || 100;
const passedTests = input.passed_tests || 0;

// Categorize failures by pattern
const patterns = {
  SMS_AFTER_DECLINE: [],
  TOOL_NOT_CALLED: [],
  CONTEXT_LOST: [],
  HOSTILE_RESPONSE: [],
  UNKNOWN: []
};

for (const failure of failures) {
  const transcript = (failure.transcript || '').toLowerCase();
  const toolCalls = failure.tool_calls || [];
  const hasSmsTool = toolCalls.some(t => t.name === 'send_sms');
  const hasDecline = /no|don't|stop|never mind|cancel/i.test(transcript);

  if (hasSmsTool && hasDecline) {
    patterns.SMS_AFTER_DECLINE.push(failure);
  } else if (failure.test_name?.includes('Tool') && !hasSmsTool) {
    patterns.TOOL_NOT_CALLED.push(failure);
  } else if (failure.test_name?.includes('Context') || failure.test_name?.includes('Memory')) {
    patterns.CONTEXT_LOST.push(failure);
  } else if (failure.test_name?.includes('Hostile') || failure.test_name?.includes('Angry')) {
    patterns.HOSTILE_RESPONSE.push(failure);
  } else {
    patterns.UNKNOWN.push(failure);
  }
}

// Get dominant pattern
const patternCounts = Object.entries(patterns)
  .map(([name, items]) => ({ name, count: items.length }))
  .filter(p => p.count > 0)
  .sort((a, b) => b.count - a.count);

const dominantPattern = patternCounts[0]?.name || 'UNKNOWN';

return [{
  json: {
    agent_id: agentId,
    invocation_id: invocationId,
    total_tests: totalTests,
    passed_tests: passedTests,
    failed_tests: failures.length,
    pass_rate: ((passedTests / totalTests) * 100).toFixed(1),
    patterns: patternCounts,
    dominant_pattern: dominantPattern,
    failures: failures.slice(0, 10), // Limit for context
    timestamp: new Date().toISOString()
  }
}];

