// Extract the prompt addition from Gemini's response
const geminiResponse = $input.first().json;
const content = geminiResponse.choices?.[0]?.message?.content || '';

// Parse the structured response
let analysis = '';
let promptAddition = '';
let expectedImprovement = '';

const analysisMatch = content.match(/ANALYSIS:\s*([\s\S]*?)(?=PROMPT_ADDITION:|$)/i);
if (analysisMatch) analysis = analysisMatch[1].trim();

const promptMatch = content.match(/PROMPT_ADDITION:\s*([\s\S]*?)(?=EXPECTED_IMPROVEMENT:|$)/i);
if (promptMatch) promptAddition = promptMatch[1].trim();

const improvementMatch = content.match(/EXPECTED_IMPROVEMENT:\s*([\s\S]*?)$/i);
if (improvementMatch) expectedImprovement = improvementMatch[1].trim();

// Get current prompt from previous node
const currentPrompt = $('Get Agent Prompt').item.json.conversation_config?.agent?.prompt?.prompt || '';

// Create the updated prompt
const autorefinementTag = `\n\n[AUTOREFINEMENT ${new Date().toISOString().split('T')[0]}]`;
const updatedPrompt = currentPrompt + autorefinementTag + '\n' + promptAddition;

return [{
  json: {
    agent_id: $('Parse Failure Data').item.json.agent_id,
    dominant_pattern: $('Parse Failure Data').item.json.dominant_pattern,
    analysis: analysis,
    prompt_addition: promptAddition,
    expected_improvement: expectedImprovement,
    current_prompt_length: currentPrompt.length,
    updated_prompt: updatedPrompt,
    updated_prompt_length: updatedPrompt.length,
    failed_test_ids: $('Parse Failure Data').item.json.failures.map(f => f.test_id).filter(Boolean)
  }
}];

